#!/bin/bash\n# Ansible Playbook Execution Script\n# Purpose: Run Ansible playbook for infrastructure configuration\n\nset -e\n\necho \"================================================\"\necho \"  Ansible Infrastructure Configuration\"\necho \"================================================\"\n\nANSIBLE_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")/../ansible\" && pwd)\"\ncd \"$ANSIBLE_DIR\"\n\necho \"Working directory: $ANSIBLE_DIR\"\necho \"\"\n\n# Color output\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nNC='\\033[0m'\n\nlog_info() {\n    echo -e \"${GREEN}[INFO]${NC} $1\"\n}\n\nlog_warn() {\n    echo -e \"${YELLOW}[WARN]${NC} $1\"\n}\n\nlog_error() {\n    echo -e \"${RED}[ERROR]${NC} $1\"\n}\n\n# Check prerequisites\nlog_info \"Checking prerequisites...\"\n\nif ! command -v ansible &> /dev/null; then\n    log_error \"ansible not found. Please install Ansible.\"\n    log_info \"Install via: pip install ansible\"\n    exit 1\nfi\n\nif ! command -v ansible-playbook &> /dev/null; then\n    log_error \"ansible-playbook not found.\"\n    exit 1\nfi\n\nif ! command -v kubectl &> /dev/null; then\n    log_error \"kubectl not found.\"\n    exit 1\nfi\n\nif ! kubectl cluster-info &> /dev/null; then\n    log_error \"Cannot connect to Kubernetes cluster.\"\n    exit 1\nfi\n\nlog_info \"✓ Prerequisites met\"\necho \"\"\n\n# Run Ansible playbook\nlog_info \"Running Ansible playbook...\"\nlog_info \"Playbook: playbook.yml\"\nlog_info \"Inventory: inventory\"\necho \"\"\n\nansible-playbook -i inventory playbook.yml -v\n\necho \"\"\nlog_info \"================================================\"\nlog_info \"  ✓ Ansible Configuration Complete\"\nlog_info \"================================================\"\n